// Do not edit this file as it will be overwritten if HAMR codegen is rerun

use data::*;

macro_rules! implies {
  ($lhs: expr, $rhs: expr) => {
    !$lhs || $rhs
  };
}

macro_rules! impliesL {
  ($lhs: expr, $rhs: expr) => {
    !$lhs | $rhs
  };
}

/** I-Assm: Integration constraint on rcv's incoming data port in_val
  *
  * assume in_val_range
  */
pub fn I_Assm_in_val(in_val: i32) -> bool
{
  in_val >= 0i32
}

/** Initialize EntryPointContract
  *
  * guarantee initLastVal
  *   state is initialized before the first dispatch
  * @param lastVal post-state state variable
  */
pub fn initialize_initLastVal(lastVal: i32) -> bool
{
  lastVal == 0i32
}

/** IEP-Guar: Initialize Entrypoint for rcv
  *
  * @param lastVal post-state state variable
  */
pub fn initialize_IEP_Guar(lastVal: i32) -> bool
{
  initialize_initLastVal(lastVal)
}

/** IEP-Post: Initialize Entrypoint Post-Condition
  *
  * @param lastVal post-state state variable
  */
pub fn initialize_IEP_Post(lastVal: i32) -> bool
{
  initialize_IEP_Guar(lastVal)
}

/** Compute Entrypoint Contract
  *
  * assumes dataBounded
  *   a received event announces a value of at most 100; the
  *   integration constraint provides the lower bound of 0
  * @param api_evt incoming event port
  * @param api_in_val incoming data port
  */
pub fn compute_spec_dataBounded_assume(
  api_evt: Option<u8>,
  api_in_val: i32) -> bool
{
  implies!(
    api_evt.is_some(),
    (api_in_val <= 100i32))
}

/** CEP-T-Assm: Top-level assume contracts for rcv's compute entrypoint
  *
  * @param api_evt incoming event port
  * @param api_in_val incoming data port
  */
pub fn compute_CEP_T_Assm(
  api_evt: Option<u8>,
  api_in_val: i32) -> bool
{
  let r0: bool = compute_spec_dataBounded_assume(api_evt, api_in_val);

  return r0;
}

/** CEP-Pre: Compute Entrypoint Pre-Condition for rcv
  *
  * @param In_lastVal pre-state state variable
  * @param api_evt incoming event port
  * @param api_in_val incoming data port
  */
pub fn compute_CEP_Pre(
  In_lastVal: i32,
  api_evt: Option<u8>,
  api_in_val: i32) -> bool
{
  // I-Assm-Guard: Integration constraints for rcv's incoming ports
  let r0: bool = I_Assm_in_val(api_in_val);

  // CEP-Assm: assume clauses of rcv's compute entrypoint
  let r1: bool = compute_CEP_T_Assm(api_evt, api_in_val);

  return r0 && r1;
}

/** Compute Entrypoint Contract
  *
  * guarantee latchOnEvent
  *   record the announced value
  * @param lastVal post-state state variable
  * @param api_evt incoming event port
  * @param api_in_val incoming data port
  */
pub fn compute_spec_latchOnEvent_guarantee(
  lastVal: i32,
  api_evt: Option<u8>,
  api_in_val: i32) -> bool
{
  implies!(
    api_evt.is_some(),
    (lastVal == api_in_val))
}

/** Compute Entrypoint Contract
  *
  * guarantee holdOtherwise
  *   no event, no state change
  * @param In_lastVal pre-state state variable
  * @param lastVal post-state state variable
  * @param api_evt incoming event port
  */
pub fn compute_spec_holdOtherwise_guarantee(
  In_lastVal: i32,
  lastVal: i32,
  api_evt: Option<u8>) -> bool
{
  implies!(
    !(api_evt.is_some()),
    (lastVal == In_lastVal))
}

/** CEP-T-Guar: Top-level guarantee contracts for rcv's compute entrypoint
  *
  * @param In_lastVal pre-state state variable
  * @param lastVal post-state state variable
  * @param api_evt incoming event port
  * @param api_in_val incoming data port
  */
pub fn compute_CEP_T_Guar(
  In_lastVal: i32,
  lastVal: i32,
  api_evt: Option<u8>,
  api_in_val: i32) -> bool
{
  let r0: bool = compute_spec_latchOnEvent_guarantee(lastVal, api_evt, api_in_val);
  let r1: bool = compute_spec_holdOtherwise_guarantee(In_lastVal, lastVal, api_evt);

  return r0 && r1;
}

/** CEP-Post: Compute Entrypoint Post-Condition for rcv
  *
  * @param In_lastVal pre-state state variable
  * @param lastVal post-state state variable
  * @param api_evt incoming event port
  * @param api_in_val incoming data port
  */
pub fn compute_CEP_Post(
  In_lastVal: i32,
  lastVal: i32,
  api_evt: Option<u8>,
  api_in_val: i32) -> bool
{
  // CEP-Guar: guarantee clauses of rcv's compute entrypoint
  let r0: bool = compute_CEP_T_Guar(In_lastVal, lastVal, api_evt, api_in_val);

  return r0;
}
